// Java 25 exam prep - Concurrent collections
// Learn: update a ConcurrentHashMap with atomic per-key operations.
ConcurrentHashMap<String, Integer> counts = new ConcurrentHashMap<>();
counts.merge("ok", 1, Integer::sum); // merge avoids a separate get-then-put race.
counts.merge("ok", 1, Integer::sum);
counts.computeIfAbsent("miss", key -> 0);
counts.forEach((key, value) -> System.out.println(key + "=" + value));
